```cpp
#include <string>
#include "markdown.hpp" // Make sure to include the hoplite header

std::string markdownToHtml(const std::string& markdownText) {
    using namespace markdown; // Bring in all the Markdown parsing functionality

    // Parse Markdown and generate an internal representation (AST)
    document doc;
    doc.parse(markdownText.c_str());

    // Serialize the AST to HTML
    std::stringstream htmlStream;
    htmlStream << doc;

    return htmlStream.str();
}
```

